INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00060', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '關於租稅規避，下列敘述何者錯誤？', '["納稅者基於獲得租稅利益，違背稅法之立法目的，濫用法律形式，以非常規交易規避租稅構成 要件之該當，以達成與交易常規相當之經濟效果，為租稅規避", "於租稅規避案件，稅捐稽徵機關應根據與實質上經濟利益相當之法律形式，成立租稅上請求權， 並加徵滯納金及利息；滯納金，按應補繳稅款10%計算", "租稅規避案件，主管機關不得另課予逃漏稅捐之處罰；但納稅者於申報或調查時，對重要事項 隱匿或為虛偽不實陳述或提供不正確資料，致使稅捐稽徵機關短漏核定稅捐者，不在此限", "租稅規避案件應徵之利息，自應補繳稅款原應繳納期限屆滿之次日起，至填發補繳稅款繳納通 知書之日止，按補繳稅款，依各年度1月1日郵政儲金一年期定期儲金固定利率，按日加計利 息，一併徵收"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00061', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '關於稅捐保全措施，下列敘述何者錯誤？', '["納稅義務人欠繳應納稅捐者，稅捐稽徵機關得就納稅義務人相當於應繳稅捐數額之財產，通知 有關機關，不得為移轉或設定他項權利", "納稅義務人有隱匿或移轉財產、逃避稅捐執行之跡象者，稅捐稽徵機關得於繳納通知文書送達 後，聲請法院就其財產實施假扣押，並免提供擔保", "在中華民國境內居住之個人，其已確定之應納稅捐逾法定繳納期限尚未繳納完畢，所欠繳稅款 及已確定之罰鍰單計或合計在新臺幣100萬元以上，得由財政部函請內政部移民署限制其出境", "限制出境之期間，自內政部移民署限制出境之日起，不得逾四年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00062', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '某甲於民國110年購入臺北市房屋一棟，若未來出售要適用自住房地優惠稅率，則須由下列何人 辦理戶籍登記？', '["本人或其配偶、未成年子女", "本人或其配偶、子女", "本人或其配偶、直系親屬", "本人或其配偶、親屬"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00063', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '綜合所得稅的減免優惠項目中，下列何者並非以自所得總額中減除之方式完成？', '["免稅額", "投資抵減", "財產交易損失", "購屋借款利息"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00064', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '符合所得稅法第 39 條盈虧互抵規定之營利事業，民國 114 年度之所得額可以減除那些年度之核 定虧損？', '["105至114年度", "110至114年度", "104至113年度", "109至113年度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00065', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依所得稅法第 43 條之 4 規定，依外國法律設立，實際管理處所在中華民國境內之營利事業，應 視為總機構在境內之營利事業，其條件不包括下列何者？', '["實際資金來源地在境內", "在境內有實際執行主要經營活動", "會計帳簿紀錄之製作或儲存處所在境內", "作成重大經營管理決策之處所在境內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00066', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '個人及營利事業交易民國105年1月1日以後取得之房屋、房屋及其坐落基地或依法得核發建造 執照之土地（以下合稱房屋、土地），有下列何種情形者，無法符合免納所得稅之規定？', '["尚未被徵收前移轉依都市計畫法指定之公共設施保留地", "個人自住房屋、土地，依法計算所得額為300萬元，辦竣戶籍登記、持有並居住於該房屋連續 滿五年，交易前五年內，無出租、供營業或執行業務使用，且個人與其配偶及未成年子女於交 易前五年內未曾適用本自住免稅規定", "被徵收或被徵收前先行協議價購之土地及其土地改良物", "符合農業發展條例第37條及第38條之1規定得申請不課徵土地增值稅之土地"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00067', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '計算營利事業所得時，下列何者可列為費用？', '["以運輸貨物為目的，於運輸時直接所支付之交際應酬費用，經取得確實單據，但其金額有一定 的比例上限", "家庭之費用", "依法繳納之罰鍰", "地震造成工廠損害，全數獲得保險理賠"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00068', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '某甲工作40年7個月後於民國113年退休，關於其退休金之領取與課稅規定，下列敘述何者錯 誤？', '["某甲退職服務年資之尾數滿六個月，以一年計", "一次領取總額在198,000元乘以退職服務年資之金額以下者，所得額為零", "一次領取超過398,000元乘以退職服務年資之金額部分，全數為所得額", "分期領取退職所得者，以全年領取總額，減除100萬元後之餘額為所得額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00069', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-114-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '經營飲食業之小規模營業人，自民國114年度起其營業稅起徵點為每月銷售額新臺幣多少萬元？', '["8萬元", "10萬元", "12萬元", "20萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "ebc056a8d8b9", "answer_pdf_sha1": "eec9f9a30014", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "508", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
